# Day 196: Cloud: Intro to AWS vs GCP vs Azure — Which to Learn
# Cloud comparison
cloud = {
    "AWS": {"ML": "SageMaker", "Compute": "EC2", "Storage": "S3", "Market": "33%"},
    "GCP": {"ML": "Vertex AI", "Compute": "Compute Engine", "Storage": "GCS", "Market": "11%"},
    "Azure": {"ML": "Azure ML", "Compute": "VMs", "Storage": "Blob", "Market": "22%"}
}
for provider, info in cloud.items():
    print(f"\n{provider}:")
    for k, v in info.items():
        print(f"  {k}: {v}")
